class Logger {
  level = 'info';
  log(msg: string) { console.log(msg); }
}
export const defaultLogger = new Logger();

// Version A: controlled accessor
class ServiceA {
  private static instance: ServiceA | null = null;
  private constructor() {}
  static getInstance(): ServiceA {
    if (!ServiceA.instance) ServiceA.instance = new ServiceA();
    return ServiceA.instance;
  }
  doWork() {}
}

// Version B: eager module export
class ServiceB {
  doWork() {}
}
export const serviceB = new ServiceB();
